"""
╔══════════════════════════════════════════════════════════════════════════════╗
║  CLOCKFIELD-GATED MOIRÉ TRANSFORMER                                          ║
║  The Unified Architecture                                                    ║
║                                                                              ║
║  Core Principle:                                                             ║
║  The Clockfield metric Γ = 1/(1 + τ·β)² does NOT live in the optimizer.     ║
║  It lives inside the forward pass, governing phase dynamics directly.        ║
║                                                                              ║
║  When a Moiré attention head encounters destructive interference             ║
║  (phase mismatch → high local "frustration"), the Clockfield metric          ║
║  dilates local time: the theta gate slows its oscillation, holding its       ║
║  phase steady while the rest of the field aligns.                            ║
║                                                                              ║
║  When the field finds constructive interference (phase alignment →           ║
║  low frustration), time normalizes and the geometry locks into place.         ║
║                                                                              ║
║  This is frustration-driven plasticity implemented as forward-pass physics,  ║
║  not backward-pass gradient surgery.                                         ║
║                                                                              ║
║  Architecture:                                                               ║
║    Moiré Attention + Clockfield Phase Gate + Frustration-Modulated MLP       ║
║                                                                              ║
║  Antti Luode — PerceptionLab, Finland                                        ║
║  Claude (Anthropic) — Architecture design                                    ║
║  March 2026                                                                  ║
╚══════════════════════════════════════════════════════════════════════════════╝
"""

import torch
import torch.nn as nn
import torch.nn.functional as F
import math
from dataclasses import dataclass, field
from typing import Optional, Tuple


# ============================================================================
# 1. CONFIGURATION
# ============================================================================

@dataclass
class ClockfieldMoireConfig:
    """Unified config for the Clockfield-Gated Moiré Transformer."""
    vocab_size: int = 50257
    max_seq_len: int = 257
    n_layer: int = 6
    n_head: int = 8
    n_embd: int = 512
    gamma_slots: int = 8       # Tokens per gamma window
    dropout: float = 0.1
    bias: bool = False

    # === Clockfield Physics ===
    tau: float = 2.0           # Clockfield tension — how strongly frustration dilates time
    frustration_ema: float = 0.9  # Exponential moving average for frustration tracking
    phase_damping: float = 0.01   # Gentle damping on phase velocities (prevents runaway)

    @property
    def head_dim(self):
        return self.n_embd // self.n_head


# ============================================================================
# 2. THE CLOCKFIELD PHASE GATE
# ============================================================================

class ClockfieldPhaseGate(nn.Module):
    """
    The Clockfield metric, wired directly into the theta gate.

    Standard Moiré: theta_gate = cos(θ_h · cycle_dist)
    Clockfield Moiré: theta_gate = cos(θ_h · cycle_dist · Γ(frustration))

    Where Γ = 1 / (1 + τ · β)²

    β (frustration) = running measure of local destructive interference.

    When frustration is high (destructive interference between Q and K phases):
      → Γ drops toward 0
      → The theta gate oscillation SLOWS DOWN (time dilation)
      → The head holds its current phase, waiting for alignment

    When frustration is low (constructive interference):
      → Γ ≈ 1
      → Normal theta gating speed
      → The geometry locks in

    This IS the Deerskin Architecture's frustration plasticity,
    implemented as differentiable forward-pass physics.
    """

    def __init__(self, config: ClockfieldMoireConfig):
        super().__init__()
        self.config = config
        self.n_head = config.n_head
        self.gamma_slots = config.gamma_slots
        self.tau = config.tau

        # Per-head learned theta frequency (as in standard Moiré)
        self.theta_offset = nn.Parameter(torch.randn(config.n_head) * 0.1)

        # Per-head frustration accumulator (running EMA, not a parameter)
        # This is the "memory" of recent destructive interference
        self.register_buffer(
            'frustration_ema',
            torch.zeros(config.n_head),
            persistent=False
        )
        self.ema_decay = config.frustration_ema

    def compute_frustration(self, interference_scores: torch.Tensor) -> torch.Tensor:
        """
        Measure frustration from the raw interference scores.

        High variance in scores = the head is confused, getting mixed signals.
        Low variance = the head has found a clear resonance pattern.

        frustration_h = std(scores) across the (T_q, T_k) attention matrix
        normalized to [0, ∞).

        Args:
            interference_scores: (B, H, T_q, T_k) raw Moiré scores before softmax

        Returns:
            frustration: (H,) per-head frustration measure
        """
        # Variance of attention scores per head (averaged across batch)
        # High variance → head is "confused" → high frustration
        # Low variance → head has clear pattern → low frustration
        with torch.no_grad():
            # Use the spread of the score distribution as frustration
            score_std = interference_scores.std(dim=-1).mean(dim=(0, 2))  # (H,)
            # Normalize: divide by sqrt(head_dim) to make it scale-invariant
            frustration = score_std / math.sqrt(self.config.head_dim)
        return frustration

    def clockfield_gamma(self, frustration: torch.Tensor) -> torch.Tensor:
        """
        The Clockfield metric: Γ = 1 / (1 + τ · β)²

        This is the SAME equation from the Clockfield optimizer,
        but now it modulates phase velocity instead of gradient magnitude.

        Args:
            frustration: (H,) per-head frustration

        Returns:
            gamma: (H,) time-dilation factor per head, in (0, 1]
        """
        return 1.0 / (1.0 + self.tau * frustration) ** 2

    def forward(self, T: int, interference_scores: torch.Tensor,
                device: torch.device) -> torch.Tensor:
        """
        Compute the Clockfield-modulated theta gate.

        Args:
            T: sequence length
            interference_scores: (B, H, T_q, T_k) raw Moiré scores
            device: torch device

        Returns:
            theta_gate: (1, H, T, T) multiplicative gate on attention scores
        """
        if T <= self.gamma_slots:
            return torch.ones(1, self.n_head, T, T, device=device)

        # 1. Measure current frustration
        current_frustration = self.compute_frustration(interference_scores)

        # 2. Update running EMA (only during training)
        if self.training:
            self.frustration_ema = (
                self.ema_decay * self.frustration_ema +
                (1 - self.ema_decay) * current_frustration
            )
            frustration = self.frustration_ema
        else:
            frustration = current_frustration

        # 3. Compute Clockfield metric Γ per head
        gamma = self.clockfield_gamma(frustration)  # (H,)

        # 4. Build the theta gate with time-dilated oscillation
        positions = torch.arange(T, device=device, dtype=torch.float32)
        cycle_ids = positions / self.gamma_slots
        cycle_dist = cycle_ids.unsqueeze(0) - cycle_ids.unsqueeze(1)  # (T, T)

        # θ_h modulated by Γ: when frustrated, the gate oscillates slower
        theta_h = self.theta_offset  # (H,)
        gamma_h = gamma  # (H,)

        # The key equation: cos(θ_h · Γ_h · cycle_dist)
        # When Γ → 0 (high frustration): gate → cos(0) = 1 everywhere
        #   → The head attends uniformly, "waiting" for alignment
        # When Γ → 1 (low frustration): gate → cos(θ_h · cycle_dist)
        #   → Normal periodic modulation, head has locked in
        effective_theta = theta_h * gamma_h  # (H,)
        theta_gate = torch.cos(
            effective_theta.view(self.n_head, 1, 1) * cycle_dist.unsqueeze(0)
        )  # (H, T, T)

        return theta_gate.unsqueeze(0)  # (1, H, T, T)


# ============================================================================
# 3. CLOCKFIELD MOIRÉ ATTENTION
# ============================================================================

class ClockfieldMoireAttention(nn.Module):
    """
    Moiré Attention with Clockfield phase gating.

    The score computation is identical to standard Moiré:
      score = Re[Q_c · conj(K_c)] / √D

    But the theta gate is now Clockfield-modulated:
      gated_score = score · cos(θ_h · Γ_h · cycle_dist)

    Where Γ_h is computed FROM the scores themselves —
    a self-referential loop where the field's own interference
    pattern governs its temporal dynamics.
    """

    def __init__(self, config: ClockfieldMoireConfig):
        super().__init__()
        self.config = config
        self.n_head = config.n_head
        self.head_dim = config.head_dim
        self.n_embd = config.n_embd

        # Q/K project to 2x (amplitude + phase), V stays real
        self.q_proj = nn.Linear(config.n_embd, 2 * config.n_embd, bias=config.bias)
        self.k_proj = nn.Linear(config.n_embd, 2 * config.n_embd, bias=config.bias)
        self.v_proj = nn.Linear(config.n_embd, config.n_embd, bias=config.bias)
        self.out_proj = nn.Linear(config.n_embd, config.n_embd, bias=config.bias)

        self.attn_dropout = nn.Dropout(config.dropout)
        self.resid_dropout = nn.Dropout(config.dropout)

        # The Clockfield phase gate (replaces the simple theta gate)
        self.phase_gate = ClockfieldPhaseGate(config)

        self.scale = 1.0 / math.sqrt(config.head_dim)

    def forward(self, x: torch.Tensor,
                attention_mask: Optional[torch.Tensor] = None
                ) -> Tuple[torch.Tensor, dict]:
        B, T, C = x.shape

        # Project to complex-valued Q, K
        q_raw = self.q_proj(x)
        k_raw = self.k_proj(x)
        v = self.v_proj(x).view(B, T, self.n_head, self.head_dim).transpose(1, 2)

        q_amp, q_phase = q_raw.chunk(2, dim=-1)
        k_amp, k_phase = k_raw.chunk(2, dim=-1)

        q_amp = F.softplus(q_amp.view(B, T, self.n_head, self.head_dim).transpose(1, 2))
        q_phase = q_phase.view(B, T, self.n_head, self.head_dim).transpose(1, 2)
        k_amp = F.softplus(k_amp.view(B, T, self.n_head, self.head_dim).transpose(1, 2))
        k_phase = k_phase.view(B, T, self.n_head, self.head_dim).transpose(1, 2)

        # Moiré interference: Re[Q_c · conj(K_c)]
        q_real = q_amp * torch.cos(q_phase)
        q_imag = q_amp * torch.sin(q_phase)
        k_real = k_amp * torch.cos(k_phase)
        k_imag = k_amp * torch.sin(k_phase)

        real_scores = torch.matmul(q_real, k_real.transpose(-1, -2))
        imag_scores = torch.matmul(q_imag, k_imag.transpose(-1, -2))
        scores = (real_scores + imag_scores) * self.scale  # (B, H, T, T)

        # === THE CLOCKFIELD GATE ===
        # The scores THEMSELVES determine the time dilation of the theta gate.
        # This is the self-referential physics loop:
        #   interference → frustration → time dilation → gating → output
        theta_gate = self.phase_gate(T, scores, x.device)
        gated_scores = scores * theta_gate

        # Causal mask
        causal_mask = torch.tril(torch.ones(T, T, device=x.device, dtype=torch.bool))
        gated_scores = gated_scores.masked_fill(
            ~causal_mask.unsqueeze(0).unsqueeze(0), float('-inf')
        )

        if attention_mask is not None:
            gated_scores = gated_scores + attention_mask

        attn_weights = self.attn_dropout(F.softmax(gated_scores, dim=-1))
        out = torch.matmul(attn_weights, v)
        out = out.transpose(1, 2).contiguous().view(B, T, C)
        out = self.resid_dropout(self.out_proj(out))

        # Collect diagnostics for logging
        diagnostics = {
            'frustration': self.phase_gate.frustration_ema.detach().clone(),
            'gamma': self.phase_gate.clockfield_gamma(
                self.phase_gate.frustration_ema
            ).detach().clone(),
            'theta_effective': (
                self.phase_gate.theta_offset *
                self.phase_gate.clockfield_gamma(self.phase_gate.frustration_ema)
            ).detach().clone(),
        }

        return out, diagnostics


# ============================================================================
# 4. FRUSTRATION-MODULATED MLP
# ============================================================================

class ClockfieldMLP(nn.Module):
    """
    MLP with optional Clockfield modulation.

    The idea: if the attention layer was frustrated (high β),
    the MLP should also be cautious — applying a softer nonlinearity
    to avoid amplifying noise from a confused attention pattern.

    When Γ → 0 (frustrated): activation → linear pass-through
    When Γ → 1 (confident): activation → full GELU nonlinearity

    This is implemented as: output = Γ · GELU(x) + (1-Γ) · x
    A smooth interpolation between nonlinear processing and identity.
    """

    def __init__(self, config: ClockfieldMoireConfig):
        super().__init__()
        self.fc1 = nn.Linear(config.n_embd, 4 * config.n_embd, bias=config.bias)
        self.fc2 = nn.Linear(4 * config.n_embd, config.n_embd, bias=config.bias)
        self.dropout = nn.Dropout(config.dropout)

        # Learnable sensitivity to the Clockfield signal
        self.gamma_sensitivity = nn.Parameter(torch.tensor(1.0))

    def forward(self, x: torch.Tensor,
                gamma: Optional[torch.Tensor] = None) -> torch.Tensor:
        h = self.fc1(x)

        if gamma is not None and gamma.numel() > 0:
            # Average gamma across heads → single scalar confidence measure
            mean_gamma = gamma.mean().clamp(0.0, 1.0)
            # Scale by learnable sensitivity
            g = (mean_gamma * self.gamma_sensitivity).clamp(0.0, 1.0)
            # Interpolate: frustrated → linear, confident → GELU
            h = g * F.gelu(h) + (1.0 - g) * h
        else:
            h = F.gelu(h)

        return self.dropout(self.fc2(h))


# ============================================================================
# 5. TRANSFORMER BLOCK
# ============================================================================

class ClockfieldMoireBlock(nn.Module):
    """
    One transformer block with Clockfield-gated Moiré attention
    and frustration-modulated MLP.

    The Clockfield signal flows: attention → diagnostics → MLP modulation
    """

    def __init__(self, config: ClockfieldMoireConfig):
        super().__init__()
        self.ln1 = nn.LayerNorm(config.n_embd)
        self.attn = ClockfieldMoireAttention(config)
        self.ln2 = nn.LayerNorm(config.n_embd)
        self.mlp = ClockfieldMLP(config)

    def forward(self, x: torch.Tensor,
                attention_mask: Optional[torch.Tensor] = None
                ) -> Tuple[torch.Tensor, dict]:
        # Attention with Clockfield gating
        attn_out, diagnostics = self.attn(self.ln1(x), attention_mask)
        x = x + attn_out

        # MLP modulated by the Clockfield confidence
        gamma = diagnostics.get('gamma', None)
        x = x + self.mlp(self.ln2(x), gamma)

        return x, diagnostics


# ============================================================================
# 6. THE FULL MODEL
# ============================================================================

class ClockfieldMoireGPT(nn.Module):
    """
    The Clockfield-Gated Moiré Transformer.

    A GPT-style autoregressive language model where:
    - Attention uses phase-interference scoring (Moiré)
    - The theta gate is modulated by the Clockfield metric
    - The Clockfield metric is computed FROM the interference pattern
    - The MLP nonlinearity is softened when attention is frustrated
    - Standard backpropagation trains the weights (AdamW)
    - The Clockfield operates as forward-pass physics, not optimizer surgery

    This unifies:
    - The Deerskin Architecture (phase-space geometry)
    - The Clockfield metric (time dilation from frustration)
    - Moiré Attention (interference-based scoring)
    Into a single differentiable system.
    """

    def __init__(self, config: ClockfieldMoireConfig):
        super().__init__()
        self.config = config

        self.tok_emb = nn.Embedding(config.vocab_size, config.n_embd)
        self.pos_emb = nn.Embedding(config.max_seq_len, config.n_embd)
        self.drop = nn.Dropout(config.dropout)

        self.blocks = nn.ModuleList([
            ClockfieldMoireBlock(config) for _ in range(config.n_layer)
        ])

        self.ln_f = nn.LayerNorm(config.n_embd)
        self.lm_head = nn.Linear(config.n_embd, config.vocab_size, bias=False)

        # Weight tying
        self.tok_emb.weight = self.lm_head.weight

        self.apply(self._init_weights)
        n_params = sum(p.numel() for p in self.parameters() if p.requires_grad)
        print(f"[Clockfield-Moiré GPT] {n_params/1e6:.1f}M parameters")

    def _init_weights(self, module):
        if isinstance(module, nn.Linear):
            torch.nn.init.normal_(module.weight, mean=0.0, std=0.02)
            if module.bias is not None:
                torch.nn.init.zeros_(module.bias)
        elif isinstance(module, nn.Embedding):
            torch.nn.init.normal_(module.weight, mean=0.0, std=0.02)

    def forward(self, input_ids: torch.Tensor,
                targets: Optional[torch.Tensor] = None,
                attention_mask: Optional[torch.Tensor] = None
                ) -> Tuple[torch.Tensor, Optional[torch.Tensor], dict]:
        B, T = input_ids.shape
        pos = torch.arange(0, T, device=input_ids.device).unsqueeze(0)

        x = self.drop(self.tok_emb(input_ids) + self.pos_emb(pos))

        # Collect per-layer diagnostics
        all_diagnostics = []
        for block in self.blocks:
            x, diag = block(x, attention_mask)
            all_diagnostics.append(diag)

        logits = self.lm_head(self.ln_f(x))

        loss = None
        if targets is not None:
            loss = F.cross_entropy(
                logits.reshape(-1, logits.size(-1)),
                targets.reshape(-1),
                ignore_index=-100
            )

        # Aggregate diagnostics across layers
        summary = {}
        if all_diagnostics:
            frustrations = torch.stack([d['frustration'] for d in all_diagnostics])
            gammas = torch.stack([d['gamma'] for d in all_diagnostics])
            summary = {
                'frustration_per_layer': frustrations,  # (L, H)
                'gamma_per_layer': gammas,              # (L, H)
                'mean_frustration': frustrations.mean().item(),
                'mean_gamma': gammas.mean().item(),
                'min_gamma': gammas.min().item(),
                'max_gamma': gammas.max().item(),
            }

        return logits, loss, summary

    @torch.no_grad()
    def generate(self, input_ids: torch.Tensor, max_new_tokens: int = 50,
                 temperature: float = 0.8, top_k: int = 40) -> torch.Tensor:
        for _ in range(max_new_tokens):
            idx_cond = input_ids[:, -self.config.max_seq_len:]
            logits, _, _ = self(idx_cond)
            logits = logits[:, -1, :] / temperature
            if top_k is not None:
                v, _ = torch.topk(logits, min(top_k, logits.size(-1)))
                logits[logits < v[:, [-1]]] = float('-inf')
            probs = F.softmax(logits, dim=-1)
            next_token = torch.multinomial(probs, num_samples=1)
            input_ids = torch.cat([input_ids, next_token], dim=1)
        return input_ids


# ============================================================================
# 7. BASELINE: STANDARD MOIRÉ (for controlled comparison)
# ============================================================================

class StandardMoireAttention(nn.Module):
    """Standard Moiré attention WITHOUT Clockfield gating. For A/B comparison."""

    def __init__(self, config: ClockfieldMoireConfig):
        super().__init__()
        self.config = config
        self.n_head = config.n_head
        self.head_dim = config.head_dim
        self.n_embd = config.n_embd
        self.gamma_slots = config.gamma_slots

        self.q_proj = nn.Linear(config.n_embd, 2 * config.n_embd, bias=config.bias)
        self.k_proj = nn.Linear(config.n_embd, 2 * config.n_embd, bias=config.bias)
        self.v_proj = nn.Linear(config.n_embd, config.n_embd, bias=config.bias)
        self.out_proj = nn.Linear(config.n_embd, config.n_embd, bias=config.bias)

        self.attn_dropout = nn.Dropout(config.dropout)
        self.resid_dropout = nn.Dropout(config.dropout)

        self.theta_offset = nn.Parameter(torch.randn(config.n_head) * 0.1)
        self.scale = 1.0 / math.sqrt(config.head_dim)

    def forward(self, x, attention_mask=None):
        B, T, C = x.shape

        q_raw = self.q_proj(x)
        k_raw = self.k_proj(x)
        v = self.v_proj(x).view(B, T, self.n_head, self.head_dim).transpose(1, 2)

        q_amp, q_phase = q_raw.chunk(2, dim=-1)
        k_amp, k_phase = k_raw.chunk(2, dim=-1)

        q_amp = F.softplus(q_amp.view(B, T, self.n_head, self.head_dim).transpose(1, 2))
        q_phase = q_phase.view(B, T, self.n_head, self.head_dim).transpose(1, 2)
        k_amp = F.softplus(k_amp.view(B, T, self.n_head, self.head_dim).transpose(1, 2))
        k_phase = k_phase.view(B, T, self.n_head, self.head_dim).transpose(1, 2)

        q_real = q_amp * torch.cos(q_phase)
        q_imag = q_amp * torch.sin(q_phase)
        k_real = k_amp * torch.cos(k_phase)
        k_imag = k_amp * torch.sin(k_phase)

        real_scores = torch.matmul(q_real, k_real.transpose(-1, -2))
        imag_scores = torch.matmul(q_imag, k_imag.transpose(-1, -2))
        scores = (real_scores + imag_scores) * self.scale

        # Standard theta gating (no Clockfield)
        if T > self.gamma_slots:
            positions = torch.arange(T, device=x.device, dtype=torch.float32)
            cycle_ids = positions / self.gamma_slots
            cycle_dist = cycle_ids.unsqueeze(0) - cycle_ids.unsqueeze(1)
            theta_off = self.theta_offset.view(self.n_head, 1, 1)
            theta_gate = torch.cos(theta_off * cycle_dist.unsqueeze(0))
            scores = scores * theta_gate.unsqueeze(0)

        causal_mask = torch.tril(torch.ones(T, T, device=x.device, dtype=torch.bool))
        scores = scores.masked_fill(~causal_mask.unsqueeze(0).unsqueeze(0), float('-inf'))

        if attention_mask is not None:
            scores = scores + attention_mask

        attn_weights = self.attn_dropout(F.softmax(scores, dim=-1))
        out = torch.matmul(attn_weights, v)
        out = out.transpose(1, 2).contiguous().view(B, T, C)
        return self.resid_dropout(self.out_proj(out)), {}


class StandardMoireBlock(nn.Module):
    def __init__(self, config):
        super().__init__()
        self.ln1 = nn.LayerNorm(config.n_embd)
        self.attn = StandardMoireAttention(config)
        self.ln2 = nn.LayerNorm(config.n_embd)
        self.mlp = nn.Sequential(
            nn.Linear(config.n_embd, 4 * config.n_embd, bias=config.bias),
            nn.GELU(),
            nn.Linear(4 * config.n_embd, config.n_embd, bias=config.bias),
            nn.Dropout(config.dropout),
        )

    def forward(self, x, attention_mask=None):
        attn_out, diag = self.attn(self.ln1(x), attention_mask)
        x = x + attn_out
        x = x + self.mlp(self.ln2(x))
        return x, diag


class StandardMoireGPT(nn.Module):
    """Standard Moiré GPT (no Clockfield) for controlled A/B comparison."""

    def __init__(self, config: ClockfieldMoireConfig):
        super().__init__()
        self.config = config
        self.tok_emb = nn.Embedding(config.vocab_size, config.n_embd)
        self.pos_emb = nn.Embedding(config.max_seq_len, config.n_embd)
        self.drop = nn.Dropout(config.dropout)
        self.blocks = nn.ModuleList([
            StandardMoireBlock(config) for _ in range(config.n_layer)
        ])
        self.ln_f = nn.LayerNorm(config.n_embd)
        self.lm_head = nn.Linear(config.vocab_size, config.n_embd, bias=False)
        # Fix: lm_head should be n_embd -> vocab_size
        self.lm_head = nn.Linear(config.n_embd, config.vocab_size, bias=False)
        self.tok_emb.weight = self.lm_head.weight
        self.apply(self._init_weights)
        n_params = sum(p.numel() for p in self.parameters() if p.requires_grad)
        print(f"[Standard Moiré GPT] {n_params/1e6:.1f}M parameters")

    def _init_weights(self, module):
        if isinstance(module, nn.Linear):
            torch.nn.init.normal_(module.weight, mean=0.0, std=0.02)
            if module.bias is not None:
                torch.nn.init.zeros_(module.bias)
        elif isinstance(module, nn.Embedding):
            torch.nn.init.normal_(module.weight, mean=0.0, std=0.02)

    def forward(self, input_ids, targets=None, attention_mask=None):
        B, T = input_ids.shape
        pos = torch.arange(0, T, device=input_ids.device).unsqueeze(0)
        x = self.drop(self.tok_emb(input_ids) + self.pos_emb(pos))
        for block in self.blocks:
            x, _ = block(x, attention_mask)
        logits = self.lm_head(self.ln_f(x))
        loss = None
        if targets is not None:
            loss = F.cross_entropy(
                logits.reshape(-1, logits.size(-1)),
                targets.reshape(-1), ignore_index=-100
            )
        return logits, loss, {}

    @torch.no_grad()
    def generate(self, input_ids, max_new_tokens=50, temperature=0.8, top_k=40):
        for _ in range(max_new_tokens):
            idx_cond = input_ids[:, -self.config.max_seq_len:]
            logits, _, _ = self(idx_cond)
            logits = logits[:, -1, :] / temperature
            if top_k is not None:
                v, _ = torch.topk(logits, min(top_k, logits.size(-1)))
                logits[logits < v[:, [-1]]] = float('-inf')
            probs = F.softmax(logits, dim=-1)
            next_token = torch.multinomial(probs, num_samples=1)
            input_ids = torch.cat([input_ids, next_token], dim=1)
        return input_ids


