# ======================================

"""
╔══════════════════════════════════════════════════════════════════════════════╗
║  CLOCKFIELD-MOIRÉ TRAINER                                                    ║
║  Head-to-Head: Clockfield-Gated Moiré vs Standard Moiré                     ║
║                                                                              ║
║  The experiment that answers:                                                ║
║  Does wiring the Clockfield metric into the forward pass                     ║
║  (as phase-velocity modulation) outperform standard Moiré attention?         ║
║                                                                              ║
║  Both models use:                                                            ║
║    - Identical architecture (layers, heads, embedding dim)                   ║
║    - Identical data (WikiText-2)                                             ║
║    - Identical optimizer (AdamW — the Clockfield is NOT in the optimizer)    ║
║    - Identical hyperparameters                                               ║
║                                                                              ║
║  The ONLY difference:                                                        ║
║    Standard: theta_gate = cos(θ_h · cycle_dist)                              ║
║    Clockfield: theta_gate = cos(θ_h · Γ(frustration) · cycle_dist)           ║
║    + MLP interpolation: Γ·GELU(x) + (1-Γ)·x                                ║
║                                                                              ║
║  Usage:                                                                      ║
║    python train_clockfield_moire.py                                          ║
║    python train_clockfield_moire.py --epochs 5 --n_layer 6 --n_embd 512     ║
║    python train_clockfield_moire.py --device cpu --epochs 2                  ║
║                                                                              ║
║  Antti Luode — PerceptionLab, Finland                                        ║
║  Claude (Anthropic) — Architecture design                                    ║
║  March 2026                                                                  ║
╚══════════════════════════════════════════════════════════════════════════════╝
"""

import torch
import torch.nn.functional as F
import math
import time
import argparse
import json
import os
import numpy as np

from clockfield_moire_unified import (
    ClockfieldMoireConfig,
    ClockfieldMoireGPT,
    StandardMoireGPT,
)


# ============================================================================
# 1. DATA PIPELINE
# ============================================================================

def load_wikitext2(tokenizer, seq_len: int):
    """Load WikiText-2 and chunk into training sequences."""
    from datasets import load_dataset
    print("Loading WikiText-2...")
    ds = load_dataset("wikitext", "wikitext-2-raw-v1", split="train")
    text = "\n".join([t for t in ds["text"] if len(t.strip()) > 20])

    tokens = tokenizer.encode(text)
    print(f"  Total tokens: {len(tokens):,}")

    n_seqs = len(tokens) // seq_len
    tokens = tokens[: n_seqs * seq_len]
    data = torch.tensor(tokens, dtype=torch.long).view(n_seqs, seq_len)
    print(f"  Training sequences: {n_seqs:,} × {seq_len} tokens")
    return data


def load_mixed_dataset(tokenizer, seq_len: int, max_tokens_per_set: int = 200000):
    """Load a 4-dataset mix for richer training."""
    from datasets import load_dataset
    print("Loading Mixed Dataset (Guanaco + TinyStories + FineWeb + WikiText)...")

    all_tokens = []
    datasets_info = [
        ("Guanaco", "timdettmers/openassistant-guanaco", "train", "text", None),
        ("TinyStories", "roneneldan/TinyStories", "train", "text", None),
        ("FineWeb-Edu", "HuggingFaceFW/fineweb-edu", "train", "text", "sample-10BT"),
        ("WikiText", "wikitext", "train", "text", "wikitext-2-raw-v1"),
    ]

    for name, path, split, col, config_name in datasets_info:
        print(f"  -> Streaming {name}...")
        try:
            ds = load_dataset(path, config_name, split=split, streaming=True)
            ds_iter = iter(ds)
            ds_tokens = []
            while len(ds_tokens) < max_tokens_per_set:
                try:
                    row = next(ds_iter)
                    text = row.get(col, "")
                    if text and len(text.strip()) > 20:
                        tokens = tokenizer.encode(text + tokenizer.eos_token)
                        ds_tokens.extend(tokens)
                except StopIteration:
                    break
            all_tokens.extend(ds_tokens[:max_tokens_per_set])
            print(f"     Loaded {len(ds_tokens[:max_tokens_per_set]):,} tokens")
        except Exception as e:
            print(f"     [!] Failed: {e}")

    print(f"  Total tokens: {len(all_tokens):,}")
    n_seqs = len(all_tokens) // seq_len
    all_tokens = all_tokens[: n_seqs * seq_len]
    data = torch.tensor(all_tokens, dtype=torch.long).view(n_seqs, seq_len)
    print(f"  Training sequences: {n_seqs:,} × {seq_len} tokens")
    return data


# ============================================================================
# 2. TRAINING LOOP
# ============================================================================

def train_model(model, train_data, config, args, model_name: str):
    """Train one model and return loss history + diagnostics."""
    device = args.device
    model = model.to(device)
    model.train()

    optimizer = torch.optim.AdamW(model.parameters(), lr=args.lr, weight_decay=0.01)

    n_batches = len(train_data) // args.batch_size
    total_steps = args.epochs * n_batches
    warmup_steps = min(200, total_steps // 10)

    def lr_schedule(step):
        if step < warmup_steps:
            return step / warmup_steps
        progress = (step - warmup_steps) / max(1, total_steps - warmup_steps)
        return 0.5 * (1.0 + math.cos(math.pi * progress))

    scheduler = torch.optim.lr_scheduler.LambdaLR(optimizer, lr_schedule)

    # Mixed precision
    use_amp = (device == 'cuda')
    scaler = torch.amp.GradScaler('cuda') if use_amp else None

    loss_history = []
    clockfield_history = []  # Γ, frustration per step
    t_start = time.time()
    global_step = 0

    print(f"\n{'='*60}")
    print(f"  TRAINING: {model_name}")
    print(f"  {sum(p.numel() for p in model.parameters())/1e6:.1f}M params")
    print(f"  {total_steps} total steps ({args.epochs} epochs × {n_batches} batches)")
    print(f"  Device: {device} | AMP: {use_amp}")
    print(f"{'='*60}\n")

    for epoch in range(args.epochs):
        perm = torch.randperm(len(train_data))
        train_data_shuffled = train_data[perm]

        epoch_loss = 0.0
        epoch_steps = 0

        for i in range(0, len(train_data_shuffled) - args.batch_size, args.batch_size):
            batch = train_data_shuffled[i : i + args.batch_size].to(device)

            optimizer.zero_grad()

            if use_amp:
                with torch.amp.autocast('cuda', dtype=torch.bfloat16):
                    logits, loss, diagnostics = model(batch[:, :-1], batch[:, 1:])
                scaler.scale(loss).backward()
                scaler.unscale_(optimizer)
                torch.nn.utils.clip_grad_norm_(model.parameters(), 1.0)
                scaler.step(optimizer)
                scaler.update()
            else:
                logits, loss, diagnostics = model(batch[:, :-1], batch[:, 1:])
                loss.backward()
                torch.nn.utils.clip_grad_norm_(model.parameters(), 1.0)
                optimizer.step()

            scheduler.step()

            loss_val = loss.item()
            loss_history.append(loss_val)
            epoch_loss += loss_val
            epoch_steps += 1
            global_step += 1

            # Log Clockfield diagnostics
            if diagnostics:
                clockfield_history.append({
                    'step': global_step,
                    'mean_frustration': diagnostics.get('mean_frustration', 0),
                    'mean_gamma': diagnostics.get('mean_gamma', 1),
                    'min_gamma': diagnostics.get('min_gamma', 1),
                    'max_gamma': diagnostics.get('max_gamma', 1),
                })

            if global_step % args.log_every == 0:
                elapsed = time.time() - t_start
                diag_str = ""
                if diagnostics and 'mean_gamma' in diagnostics:
                    diag_str = (f" | Γ={diagnostics['mean_gamma']:.3f}"
                                f" β={diagnostics['mean_frustration']:.3f}")
                print(f"  [{model_name}] Step {global_step:5d} | "
                      f"Loss: {loss_val:.4f} | "
                      f"LR: {scheduler.get_last_lr()[0]:.2e}{diag_str} | "
                      f"{elapsed:.0f}s")

        avg_loss = epoch_loss / max(epoch_steps, 1)
        print(f"  [{model_name}] === Epoch {epoch+1}/{args.epochs} "
              f"Avg Loss: {avg_loss:.4f} ===")

    # Save weights
    save_path = f"{model_name}_weights.pt"
    torch.save({
        'model_state': model.state_dict(),
        'config': {
            'n_layer': config.n_layer,
            'n_head': config.n_head,
            'n_embd': config.n_embd,
            'max_seq_len': config.max_seq_len,
            'gamma_slots': config.gamma_slots,
            'tau': config.tau if hasattr(config, 'tau') else 0,
        },
        'loss_history': loss_history,
        'clockfield_history': clockfield_history,
    }, save_path)
    print(f"  [{model_name}] Saved to {save_path}")

    return loss_history, clockfield_history


# ============================================================================
# 3. ANALYSIS & PLOTTING
# ============================================================================

def plot_comparison(clock_losses, standard_losses, clock_diag, args):
    """Generate comparison plots."""
    try:
        import matplotlib
        matplotlib.use('Agg')
        import matplotlib.pyplot as plt
    except ImportError:
        print("matplotlib not available, skipping plots")
        return

    def smooth(vals, weight=0.95):
        s = []
        last = vals[0]
        for v in vals:
            last = last * weight + (1 - weight) * v
            s.append(last)
        return s

    fig, axes = plt.subplots(2, 2, figsize=(14, 10), facecolor='#0a0a12')
    fig.suptitle('Clockfield-Gated Moiré vs Standard Moiré',
                 fontsize=16, color='#00ccff', fontweight='bold',
                 fontfamily='monospace')

    for ax in axes.flat:
        ax.set_facecolor('#0a0a12')
        ax.tick_params(colors='#4a5868', labelsize=8)
        for spine in ax.spines.values():
            spine.set_color('#1a2030')

    # Panel 1: Loss curves
    ax = axes[0, 0]
    ax.plot(smooth(standard_losses), label='Standard Moiré', color='#ff6b35',
            alpha=0.8, linewidth=1.5)
    ax.plot(smooth(clock_losses), label='Clockfield-Gated Moiré', color='#00ccff',
            alpha=0.9, linewidth=1.5)
    ax.set_title('Training Loss (Smoothed)', color='#8899aa', fontfamily='monospace')
    ax.set_xlabel('Step', color='#6a7a8a')
    ax.set_ylabel('Cross-Entropy Loss', color='#6a7a8a')
    ax.legend(facecolor='#1a1e29', edgecolor='#252b3b', labelcolor='#8899aa')
    ax.grid(True, alpha=0.1)

    # Panel 2: Final loss comparison
    ax = axes[0, 1]
    final_window = 200
    clock_final = np.mean(clock_losses[-final_window:]) if len(clock_losses) >= final_window else np.mean(clock_losses)
    std_final = np.mean(standard_losses[-final_window:]) if len(standard_losses) >= final_window else np.mean(standard_losses)
    bars = ax.bar(['Standard\nMoiré', 'Clockfield\nMoiré'],
                  [std_final, clock_final],
                  color=['#ff6b35', '#00ccff'], alpha=0.8, width=0.5)
    ax.set_title('Final Loss (last 200 steps)', color='#8899aa', fontfamily='monospace')
    ax.set_ylabel('Loss', color='#6a7a8a')
    for bar, val in zip(bars, [std_final, clock_final]):
        ax.text(bar.get_x() + bar.get_width() / 2, bar.get_height() + 0.01,
                f'{val:.4f}', ha='center', va='bottom', color='white', fontsize=10)
    delta = (std_final - clock_final) / std_final * 100
    ax.set_xlabel(f'Δ = {delta:+.2f}%', color='#34d399' if delta > 0 else '#ff6b35',
                  fontsize=12, fontweight='bold')

    # Panel 3: Clockfield Γ over training
    ax = axes[1, 0]
    if clock_diag:
        steps = [d['step'] for d in clock_diag]
        gammas = [d['mean_gamma'] for d in clock_diag]
        frustrations = [d['mean_frustration'] for d in clock_diag]
        ax.plot(steps, smooth(gammas, 0.98), label='Mean Γ (time dilation)',
                color='#a78bfa', linewidth=1.5)
        ax.plot(steps, smooth(frustrations, 0.98), label='Mean β (frustration)',
                color='#ff6b35', linewidth=1.5, alpha=0.7)
        ax.axhline(1.0, color='#334455', linestyle='--', alpha=0.5, label='Γ=1 (no dilation)')
        ax.legend(facecolor='#1a1e29', edgecolor='#252b3b', labelcolor='#8899aa', fontsize=8)
    ax.set_title('Clockfield Dynamics', color='#8899aa', fontfamily='monospace')
    ax.set_xlabel('Step', color='#6a7a8a')
    ax.set_ylabel('Value', color='#6a7a8a')
    ax.grid(True, alpha=0.1)

    # Panel 4: Per-epoch average loss
    ax = axes[1, 1]
    n_per_epoch_c = len(clock_losses) // args.epochs if args.epochs > 0 else len(clock_losses)
    n_per_epoch_s = len(standard_losses) // args.epochs if args.epochs > 0 else len(standard_losses)

    epoch_avgs_c = []
    epoch_avgs_s = []
    for e in range(args.epochs):
        c_slice = clock_losses[e * n_per_epoch_c: (e + 1) * n_per_epoch_c]
        s_slice = standard_losses[e * n_per_epoch_s: (e + 1) * n_per_epoch_s]
        if c_slice:
            epoch_avgs_c.append(np.mean(c_slice))
        if s_slice:
            epoch_avgs_s.append(np.mean(s_slice))

    epochs_x = list(range(1, len(epoch_avgs_c) + 1))
    if epoch_avgs_c and epoch_avgs_s:
        ax.plot(epochs_x, epoch_avgs_s, 'o-', label='Standard Moiré',
                color='#ff6b35', linewidth=2, markersize=6)
        ax.plot(epochs_x, epoch_avgs_c, 'o-', label='Clockfield Moiré',
                color='#00ccff', linewidth=2, markersize=6)
        # Show gap
        for i, (s, c) in enumerate(zip(epoch_avgs_s, epoch_avgs_c)):
            gap = (s - c) / s * 100
            ax.annotate(f'{gap:+.1f}%', (i + 1, (s + c) / 2),
                        color='#34d399' if gap > 0 else '#ff6b35',
                        fontsize=8, ha='center')
    ax.set_title('Per-Epoch Average Loss', color='#8899aa', fontfamily='monospace')
    ax.set_xlabel('Epoch', color='#6a7a8a')
    ax.set_ylabel('Avg Loss', color='#6a7a8a')
    ax.legend(facecolor='#1a1e29', edgecolor='#252b3b', labelcolor='#8899aa')
    ax.grid(True, alpha=0.1)

    plt.tight_layout()
    plt.savefig('clockfield_moire_comparison.png', dpi=150, facecolor=fig.get_facecolor())
    print("\nPlot saved: clockfield_moire_comparison.png")
    plt.close()


# ============================================================================
# 4. MAIN
# ============================================================================

def main():
    parser = argparse.ArgumentParser(description="Clockfield-Moiré Trainer")
    parser.add_argument('--epochs', type=int, default=3)
    parser.add_argument('--batch_size', type=int, default=8)
    parser.add_argument('--lr', type=float, default=3e-4)
    parser.add_argument('--n_layer', type=int, default=4)
    parser.add_argument('--n_head', type=int, default=8)
    parser.add_argument('--n_embd', type=int, default=256)
    parser.add_argument('--max_seq_len', type=int, default=129)
    parser.add_argument('--gamma_slots', type=int, default=8)
    parser.add_argument('--tau', type=float, default=2.0,
                        help='Clockfield tension parameter')
    parser.add_argument('--device', type=str,
                        default='cuda' if torch.cuda.is_available() else 'cpu')
    parser.add_argument('--log_every', type=int, default=50)
    parser.add_argument('--dataset', type=str, default='wikitext',
                        choices=['wikitext', 'mixed'])
    parser.add_argument('--mixed_tokens', type=int, default=200000,
                        help='Tokens per dataset in mixed mode')
    parser.add_argument('--skip_standard', action='store_true',
                        help='Skip the standard Moiré baseline (just train Clockfield)')
    args = parser.parse_args()

    print("╔══════════════════════════════════════════════════════════════╗")
    print("║  CLOCKFIELD-GATED MOIRÉ TRANSFORMER — THE GRAND EXPERIMENT  ║")
    print("╚══════════════════════════════════════════════════════════════╝")
    print()

    # Tokenizer
    from transformers import AutoTokenizer
    tokenizer = AutoTokenizer.from_pretrained('gpt2')

    # Config (shared between both models)
    config = ClockfieldMoireConfig(
        vocab_size=tokenizer.vocab_size,
        max_seq_len=args.max_seq_len,
        n_layer=args.n_layer,
        n_head=args.n_head,
        n_embd=args.n_embd,
        gamma_slots=args.gamma_slots,
        tau=args.tau,
    )

    # Data
    if args.dataset == 'wikitext':
        train_data = load_wikitext2(tokenizer, config.max_seq_len)
    else:
        train_data = load_mixed_dataset(tokenizer, config.max_seq_len, args.mixed_tokens)

    # ── Train Standard Moiré (baseline) ──
    standard_losses = []
    if not args.skip_standard:
        standard_model = StandardMoireGPT(config)
        standard_losses, _ = train_model(
            standard_model, train_data, config, args, "Standard_Moire"
        )
        del standard_model
        if args.device == 'cuda':
            torch.cuda.empty_cache()

    # ── Train Clockfield-Gated Moiré ──
    clockfield_model = ClockfieldMoireGPT(config)
    clock_losses, clock_diag = train_model(
        clockfield_model, train_data, config, args, "Clockfield_Moire"
    )

    # ── Results ──
    print("\n" + "=" * 60)
    print("  RESULTS")
    print("=" * 60)

    final_window = min(200, len(clock_losses))
    clock_final = np.mean(clock_losses[-final_window:])
    print(f"\n  Clockfield-Gated Moiré — Final loss: {clock_final:.4f}")

    if standard_losses:
        std_final = np.mean(standard_losses[-final_window:])
        delta = (std_final - clock_final) / std_final * 100
        print(f"  Standard Moiré — Final loss:         {std_final:.4f}")
        print(f"  Δ = {delta:+.2f}% {'(Clockfield wins)' if delta > 0 else '(Standard wins)'}")

    if clock_diag:
        final_diag = clock_diag[-1]
        print(f"\n  Final Clockfield state:")
        print(f"    Mean Γ (time dilation): {final_diag['mean_gamma']:.4f}")
        print(f"    Mean β (frustration):   {final_diag['mean_frustration']:.4f}")
        print(f"    Γ range: [{final_diag['min_gamma']:.4f}, {final_diag['max_gamma']:.4f}]")

    print("\n" + "=" * 60)

    # Plot
    if standard_losses:
        plot_comparison(clock_losses, standard_losses, clock_diag, args)

    # Save results JSON
    results = {
        'config': {
            'n_layer': config.n_layer, 'n_head': config.n_head,
            'n_embd': config.n_embd, 'tau': config.tau,
            'gamma_slots': config.gamma_slots, 'epochs': args.epochs,
            'lr': args.lr, 'batch_size': args.batch_size,
            'dataset': args.dataset,
        },
        'clockfield_final_loss': float(clock_final),
        'standard_final_loss': float(std_final) if standard_losses else None,
        'delta_pct': float(delta) if standard_losses else None,
        'clockfield_diagnostics_final': clock_diag[-1] if clock_diag else None,
    }
    with open('experiment_results.json', 'w') as f:
        json.dump(results, f, indent=2)
    print("Results saved: experiment_results.json")

    print("\nChat with the trained model:")
    print("  python clockfield_moire_chat.py --weights Clockfield_Moire_weights.pt")


if __name__ == "__main__":
    main()


