fig, axes = plt.subplots(2, 2, figsize=(14, 11))
fig.suptitle('Clockfield Fractal Cosmology: Quantitative Analysis', 
             fontsize=14, fontweight='bold')

# --- Panel 1: Effective dimension vs radius ---
ax1 = axes[0, 0]
