ax3.grid(True, alpha=0.3)

# --- Panel 4: Degree of divergence ---
ax4 = axes[1, 1]
L_range = range(1, 8)
for I_loops in [2, 4, 6]:
    sdod_std = [sdod_standard(L, I_loops) for L in L_range]
    sdod_calc = [sdod_calcagni(L, I_loops) for L in L_range]
    ax4.plot(L_range, sdod_std, 'r-', alpha=0.3 + 0.2*I_loops/6, 
             label=f'Standard D=4, I={I_loops}' if I_loops==2 else '')
    ax4.plot(L_range, sdod_calc, 'b--', alpha=0.3 + 0.2*I_loops/6,
             label=f'Calcagni UV, I={I_loops}' if I_loops==2 else '')

ax4.axhline(y=0, color='black', linewidth=1)
ax4.set_xlabel('Number of loops L')
ax4.set_ylabel('Superficial degree of divergence')
ax4.set_title('UV Convergence: Standard vs Fractal')
ax4.legend(fontsize=8)
