"""
MASS EQUIVALENCE SCAN
=====================

Scans M_eff/M_grav across the (τ, β₀) parameter space to determine
whether the equivalence principle holds at any special point.

If M_eff = M_grav at (τ_BPS, β₀*) for some specific β₀*, this would
mean the BPS coupling constant also enforces the equivalence principle.

Author: Antti Luode (PerceptionLab) + Claude Opus (Anthropic)
"""

import numpy as np
from scipy import integrate, optimize
import matplotlib.pyplot as plt

TAU_BPS = 2.737339


def Gamma(beta, tau):
    return 1.0 / (1.0 + tau * beta)**2


def compute_mass_ratio(tau, beta_0, sigma=1.0, n=15000, r_max=15.0):
    """Compute M_eff / M_grav for given parameters."""
    r = np.linspace(1e-6, r_max * sigma, n)
    beta = beta_0 * np.cosh(r/sigma)**(-2)
    G = Gamma(beta, tau)
    
    vol = 4.0 * np.pi * r**2
    M_grav = integrate.trapezoid((1 - G) * vol, r)
    
    A = np.sqrt(np.maximum(beta, 1e-15))
    dA_dr = -np.sqrt(beta_0)/sigma * np.cosh(r/sigma)**(-1) * np.tanh(r/sigma)
    grad_phi_sq = dA_dr**2 + beta * (1.0/r)**2
    
    M_eff = integrate.trapezoid(G**2 * grad_phi_sq * vol, r)
    
    if M_grav < 1e-10:
        return 0.0, M_grav, M_eff
    return M_eff / M_grav, M_grav, M_eff


def find_equivalence_beta0(tau=TAU_BPS):
    """
    Find β₀ where M_eff = M_grav (if it exists).
    """
    def objective(log_beta0):
        beta0 = np.exp(log_beta0)
        ratio, _, _ = compute_mass_ratio(tau, beta0)
        return ratio - 1.0
    
    # Scan first to see if a root exists
    log_b0_range = np.linspace(-2, 3, 50)
    vals = [objective(lb) for lb in log_b0_range]
    
    # Look for sign changes
    roots = []
    for i in range(len(vals)-1):
        if vals[i] * vals[i+1] < 0:
            root = optimize.brentq(objective, log_b0_range[i], log_b0_range[i+1])
            roots.append(np.exp(root))
    
    return roots


def main():
    print("=" * 65)
    print("  MASS EQUIVALENCE SCAN")
    print("  M_eff / M_grav across parameter space")
    print("=" * 65)
    print()
    
    # 1D scan: ratio vs tau at fixed beta_0
    print("Scan 1: M_eff/M_grav vs τ at β₀ = 1.0")
    taus = np.linspace(0.1, 8.0, 80)
    ratios_tau = []
    for t in taus:
        r, _, _ = compute_mass_ratio(t, 1.0)
        ratios_tau.append(r)
    ratios_tau = np.array(ratios_tau)
    
    # Find tau where ratio = 1
    crossings_tau = []
    for i in range(len(ratios_tau)-1):
        if (ratios_tau[i]-1) * (ratios_tau[i+1]-1) < 0:
            t_cross = taus[i] + (taus[i+1]-taus[i]) * (1-ratios_tau[i])/(ratios_tau[i+1]-ratios_tau[i])
            crossings_tau.append(t_cross)
    
    if crossings_tau:
        print(f"  Equivalence (M_eff=M_grav) at τ = {crossings_tau}")
    else:
        print(f"  No crossing at β₀=1.0. Ratio range: [{min(ratios_tau):.4f}, {max(ratios_tau):.4f}]")
    print()
    
    # 1D scan: ratio vs beta_0 at fixed tau
    print(f"Scan 2: M_eff/M_grav vs β₀ at τ = {TAU_BPS}")
    beta0s = np.logspace(-1, 2, 80)
    ratios_b0 = []
    for b0 in beta0s:
        r, _, _ = compute_mass_ratio(TAU_BPS, b0)
        ratios_b0.append(r)
    ratios_b0 = np.array(ratios_b0)
    
    # Find beta_0 where ratio = 1
    roots = find_equivalence_beta0(TAU_BPS)
    if roots:
        print(f"  Equivalence at β₀ = {roots}")
        for root in roots:
            ratio_check, mg, me = compute_mass_ratio(TAU_BPS, root)
            print(f"    Verification: β₀={root:.4f}, ratio={ratio_check:.6f}, "
                  f"M_grav={mg:.4f}, M_eff={me:.4f}")
    else:
        print(f"  No equivalence point found. Range: [{min(ratios_b0):.4f}, {max(ratios_b0):.4f}]")
    print()
    
    # 2D scan
    print("Scan 3: 2D parameter space (τ, β₀)")
    tau_2d = np.linspace(0.2, 6.0, 40)
    b0_2d = np.logspace(-0.5, 1.5, 40)
    ratio_grid = np.zeros((len(b0_2d), len(tau_2d)))
    
    for i, b0 in enumerate(b0_2d):
        for j, t in enumerate(tau_2d):
            r, _, _ = compute_mass_ratio(t, b0)
            ratio_grid[i, j] = r
    
    # Find the contour where ratio = 1
    print(f"  Grid computed. Ratio range: [{ratio_grid.min():.4f}, {ratio_grid.max():.4f}]")
    print(f"  At BPS point (τ={TAU_BPS}, β₀=1): ratio ≈ {ratios_tau[np.argmin(abs(taus-TAU_BPS))]:.4f}")
    print()
    
    # Summary
    print("RESULT:")
    print("  For the sech² profile with winding n=1:")
    if roots:
        print(f"  M_eff = M_grav at β₀ ≈ {roots[0]:.4f} when τ = {TAU_BPS}")
        print("  The equivalence principle IS satisfied at a specific amplitude.")
    elif any(r > 1 for r in ratios_b0):
        print("  M_eff/M_grav crosses 1.0 in the β₀ scan.")
        print("  The equivalence principle MAY be satisfied at some amplitude.")
    else:
        print("  M_eff < M_grav everywhere for this profile.")
        print("  The sech² profile does NOT satisfy the equivalence principle.")
        print("  The self-consistent solution (from the full EOM) may differ.")
    print()
    
    # ================================================================
    # PLOTS
    # ================================================================
    
    fig, axes = plt.subplots(1, 3, figsize=(16, 5))
    fig.patch.set_facecolor('#0a0a0a')
    TC = '#e0e0e0'
    
    for ax in axes:
        ax.set_facecolor('#1a1a2e')
        ax.tick_params(colors=TC, labelsize=8)
        for s in ax.spines.values(): s.set_color('#444')
        ax.grid(alpha=0.12, color='#555')
    
    # Panel 1: ratio vs tau
    ax = axes[0]
    ax.plot(taus, ratios_tau, color='#00d4ff', lw=2.5)
    ax.axhline(1.0, color='#7fff00', ls=':', lw=1, alpha=0.5)
    ax.axvline(TAU_BPS, color='#ff6b35', ls='--', lw=1.5)
    ax.set_xlabel('τ', color=TC)
    ax.set_ylabel(r'$M_{eff}/M_{grav}$', color=TC)
    ax.set_title(r'Ratio vs τ (β₀=1)', color=TC)
    ax.set_ylim(0, 2)
    
    # Panel 2: ratio vs beta_0
    ax = axes[1]
    ax.semilogx(beta0s, ratios_b0, color='#00d4ff', lw=2.5)
    ax.axhline(1.0, color='#7fff00', ls=':', lw=1, alpha=0.5)
    if roots:
        for root in roots:
            ax.axvline(root, color='#ff6b35', ls='--', lw=1.5,
                       label=f'β₀={root:.2f}')
        ax.legend(facecolor='#222', edgecolor='#444', labelcolor=TC, fontsize=8)
    ax.set_xlabel(r'$\beta_0$', color=TC)
    ax.set_ylabel(r'$M_{eff}/M_{grav}$', color=TC)
    ax.set_title(f'Ratio vs β₀ (τ={TAU_BPS:.3f})', color=TC)
    
    # Panel 3: 2D contour
    ax = axes[2]
    T2D, B2D = np.meshgrid(tau_2d, b0_2d)
    cf = ax.contourf(T2D, np.log10(B2D), ratio_grid, levels=20, cmap='RdYlGn')
    ax.contour(T2D, np.log10(B2D), ratio_grid, levels=[1.0], colors='white', linewidths=2)
    ax.axvline(TAU_BPS, color='#ff6b35', ls='--', lw=1.5)
    ax.set_xlabel('τ', color=TC)
    ax.set_ylabel(r'$\log_{10}(\beta_0)$', color=TC)
    ax.set_title(r'$M_{eff}/M_{grav}$ (white = 1)', color=TC)
    plt.colorbar(cf, ax=ax)
    
    fig.suptitle('Mass Equivalence Scan — Clockfield Two-Mass Problem', color=TC, fontsize=13)
    plt.tight_layout()
    plt.savefig('mass_equivalence.png', dpi=150, bbox_inches='tight',
                facecolor=fig.get_facecolor())
    plt.close()
    print("Plot saved: mass_equivalence.png")


if __name__ == "__main__":
    main()


