# FILE: ClockfieldHeisenberg\self_similar_closed_form.py
# ======================================

"""
SELF-SIMILAR CLOSED FORMS FOR THE CLOCKFIELD COMMUTATOR
========================================================

The exact ODE: ∂²Γ/∂β² = 6τ²Γ²

This self-similarity gives closed-form integrals via integration by parts.
These closed forms replace the numerical integrals needed for the
momentum operator and the mass equivalence calculation.

Author: Antti Luode (PerceptionLab) + Claude Opus (Anthropic)
"""

import numpy as np
from scipy import integrate
import matplotlib.pyplot as plt

TAU = 2.737339


def Gamma(beta, tau=TAU):
    return 1.0 / (1.0 + tau * beta)**2


def dGamma(beta, tau=TAU):
    return -2.0 * tau / (1.0 + tau * beta)**3


def d2Gamma(beta, tau=TAU):
    return 6.0 * tau**2 / (1.0 + tau * beta)**4


# ================================================================
# IDENTITY 1: ∫ β·Γ² dβ (momentum-related)
# ================================================================
# From ∂²Γ/∂β² = 6τ²Γ², multiply by β and integrate by parts:
#   6τ² ∫₀^B β·Γ² dβ = ∫₀^B β·Γ'' dβ
#                      = [β·Γ']₀^B - ∫₀^B Γ' dβ
#                      = B·Γ'(B) - [Γ(B) - Γ(0)]
#                      = B·Γ'(B) - Γ(B) + 1
#
# Therefore:
#   ∫₀^B β·Γ²(β) dβ = [B·Γ'(B) - Γ(B) + 1] / (6τ²)

def integral_beta_Gamma2(B, tau=TAU):
    """Exact closed form for ∫₀^B β·Γ²(β) dβ."""
    x = tau * B
    G = 1.0 / (1 + x)**2
    dG = -2.0 * tau / (1 + x)**3
    return (B * dG - G + 1.0) / (6.0 * tau**2)


# ================================================================
# IDENTITY 2: ∫ Γ² dβ (mass-related)
# ================================================================
# Direct integration:
#   ∫₀^B 1/(1+τβ)⁴ dβ = [-1/(3τ(1+τβ)³)]₀^B = (1/3τ)[1 - 1/(1+τB)³]

def integral_Gamma2(B, tau=TAU):
    """Exact closed form for ∫₀^B Γ²(β) dβ."""
    x = tau * B
    return (1.0 - 1.0/(1+x)**3) / (3.0 * tau)


# ================================================================
# IDENTITY 3: ∫ β²·Γ² dβ (second moment)
# ================================================================
# Multiply ∂²Γ/∂β² = 6τ²Γ² by β² and integrate by parts twice:
#   6τ² ∫₀^B β²·Γ² dβ = ∫₀^B β²·Γ'' dβ
#                       = [β²·Γ']₀^B - 2∫₀^B β·Γ' dβ
#                       = B²·Γ'(B) - 2[β·Γ]₀^B + 2∫₀^B Γ dβ
#                       = B²·Γ'(B) - 2B·Γ(B) + 2∫₀^B Γ dβ
#
# And ∫₀^B Γ dβ = ∫₀^B (1+τβ)⁻² dβ = (1/τ)[1 - 1/(1+τB)]
# 
# So: ∫₀^B β²·Γ² dβ = [B²·Γ'(B) - 2B·Γ(B) + (2/τ)(1-1/(1+τB))] / (6τ²)

def integral_beta2_Gamma2(B, tau=TAU):
    """Exact closed form for ∫₀^B β²·Γ²(β) dβ."""
    x = tau * B
    G = 1.0 / (1 + x)**2
    dG = -2.0 * tau / (1 + x)**3
    int_Gamma = (1.0 - 1.0/(1+x)) / tau
    return (B**2 * dG - 2*B*G + 2*int_Gamma) / (6.0 * tau**2)


# ================================================================
# IDENTITY 4: ∫ (1-Γ)·β dβ (mass-momentum cross-term)
# ================================================================
# ∫₀^B (1-Γ)β dβ = ∫₀^B β dβ - ∫₀^B β·Γ dβ
# = B²/2 - ∫₀^B β/(1+τβ)² dβ
#
# The second integral: let u = 1+τβ, β = (u-1)/τ, dβ = du/τ
# ∫ (u-1)/(τu²) · du/τ = (1/τ²)[∫ du/u - ∫ du/u²]
# = (1/τ²)[ln(u) + 1/u] evaluated from 1 to 1+τB
# = (1/τ²)[ln(1+τB) + 1/(1+τB) - 1]

def integral_one_minus_Gamma_beta(B, tau=TAU):
    """Exact closed form for ∫₀^B (1-Γ(β))·β dβ."""
    x = tau * B
    part1 = B**2 / 2.0
    part2 = (np.log(1 + x) + 1.0/(1+x) - 1.0) / tau**2
    return part1 - part2


# ================================================================
# VERIFICATION
# ================================================================

def verify_all(B=3.0, tau=TAU, n=50000):
    """Verify all closed forms against numerical integration."""
    betas = np.linspace(0, B, n)
    G = Gamma(betas, tau)
    
    tests = [
        ("∫ β·Γ² dβ",
         integral_beta_Gamma2(B, tau),
         integrate.trapezoid(betas * G**2, betas)),
        
        ("∫ Γ² dβ",
         integral_Gamma2(B, tau),
         integrate.trapezoid(G**2, betas)),
        
        ("∫ β²·Γ² dβ",
         integral_beta2_Gamma2(B, tau),
         integrate.trapezoid(betas**2 * G**2, betas)),
        
        ("∫ (1-Γ)·β dβ",
         integral_one_minus_Gamma_beta(B, tau),
         integrate.trapezoid((1-G) * betas, betas)),
    ]
    
    return tests


def main():
    print("=" * 65)
    print("SELF-SIMILAR CLOSED FORMS")
    print("From ∂²Γ/∂β² = 6τ²Γ²")
    print("=" * 65)
    print()
    
    # Verify self-similarity
    betas = np.linspace(0.01, 5.0, 1000)
    lhs = d2Gamma(betas)
    rhs = 6.0 * TAU**2 * Gamma(betas)**2
    print(f"Self-similarity max error: {np.max(np.abs(lhs-rhs)):.2e}")
    print()
    
    # Verify all identities
    for B_test in [1.0, 3.0, 5.0, 10.0]:
        print(f"β_max = {B_test}:")
        tests = verify_all(B_test)
        for name, analytical, numerical in tests:
            err = abs(analytical - numerical) / (abs(numerical) + 1e-15)
            status = "✓" if err < 1e-4 else "✗"
            print(f"  {status} {name:20s}: analytical = {analytical:.8f}, "
                  f"numerical = {numerical:.8f}, err = {err:.2e}")
        print()
    
    # The key ratio for the commutator
    print("KEY RATIO: ∫β·Γ² / ∫Γ² (momentum vs mass in β-space)")
    print(f"  {'B':>6}  {'∫β·Γ²':>12}  {'∫Γ²':>12}  {'ratio':>10}")
    print("  " + "-" * 50)
    for B in [0.5, 1.0, 2.0, 5.0, 10.0, 50.0]:
        i1 = integral_beta_Gamma2(B)
        i2 = integral_Gamma2(B)
        print(f"  {B:>6.1f}  {i1:>12.6f}  {i2:>12.6f}  {i1/i2:>10.6f}")
    
    print()
    print("As B → ∞, the ratio approaches a finite limit.")
    print("This is the β-space representation of M_eff/M_grav")
    print("(up to the Jacobian of the r↔β change of variables).")
    print()
    
    # Limit B→∞
    B_inf = 1000.0
    ratio_inf = integral_beta_Gamma2(B_inf) / integral_Gamma2(B_inf)
    print(f"Limiting ratio (B→∞): {ratio_inf:.6f}")
    print(f"For comparison: 1/(3τ) = {1/(3*TAU):.6f}")
    print()
    
    # Plot
    fig, axes = plt.subplots(1, 3, figsize=(15, 5))
    fig.patch.set_facecolor('#0a0a0a')
    TC = '#e0e0e0'
    
    for ax in axes:
        ax.set_facecolor('#1a1a2e')
        ax.tick_params(colors=TC)
        for s in ax.spines.values(): s.set_color('#444')
        ax.grid(alpha=0.12, color='#555')
    
    B_range = np.linspace(0.01, 10.0, 500)
    
    # Panel 1: The four integrals
    ax = axes[0]
    ax.plot(B_range, [integral_Gamma2(b) for b in B_range], 
            color='#00d4ff', lw=2, label=r'$\int \Gamma^2 d\beta$')
    ax.plot(B_range, [integral_beta_Gamma2(b) for b in B_range],
            color='#ff6b35', lw=2, label=r'$\int \beta\Gamma^2 d\beta$')
    ax.plot(B_range, [integral_beta2_Gamma2(b) for b in B_range],
            color='#7fff00', lw=2, label=r'$\int \beta^2\Gamma^2 d\beta$')
    ax.set_xlabel(r'$\beta_0$', color=TC)
    ax.set_title('Self-Similar Closed Forms', color=TC)
    ax.legend(facecolor='#222', edgecolor='#444', labelcolor=TC, fontsize=8)
    
    # Panel 2: The ratio ∫βΓ²/∫Γ²
    ax = axes[1]
    ratios = [integral_beta_Gamma2(b)/integral_Gamma2(b) for b in B_range]
    ax.plot(B_range, ratios, color='#00d4ff', lw=2.5)
    ax.axhline(ratio_inf, color='#ff6b35', ls='--', label=f'limit = {ratio_inf:.4f}')
    ax.set_xlabel(r'$\beta_0$', color=TC)
    ax.set_ylabel('ratio', color=TC)
    ax.set_title(r'$\int\beta\Gamma^2 / \int\Gamma^2$', color=TC)
    ax.legend(facecolor='#222', edgecolor='#444', labelcolor=TC, fontsize=8)
    
    # Panel 3: Γ and its self-similar structure
    ax = axes[2]
    betas = np.linspace(0, 5, 500)
    ax.plot(betas, Gamma(betas), color='#00d4ff', lw=2, label=r'$\Gamma(\beta)$')
    ax.plot(betas, Gamma(betas)**2, color='#ff6b35', lw=2, label=r'$\Gamma^2(\beta)$')
    ax.plot(betas, d2Gamma(betas) / (6*TAU**2), color='#7fff00', lw=1.5, ls='--',
            label=r'$\Gamma^{\prime\prime}/(6\tau^2) = \Gamma^2$')
    ax.set_xlabel(r'$\beta$', color=TC)
    ax.set_title('Self-Similarity Verification', color=TC)
    ax.legend(facecolor='#222', edgecolor='#444', labelcolor=TC, fontsize=8)
    
    fig.suptitle('Clockfield Self-Similar Integrals — Exact Closed Forms', color=TC, fontsize=13)
    plt.tight_layout()
    plt.savefig('self_similar_integrals.png', dpi=150, bbox_inches='tight',
                facecolor=fig.get_facecolor())
    plt.close()
    print("Plot saved: self_similar_integrals.png")


if __name__ == "__main__":
    main()


