import numpy as np
from scipy import integrate
import matplotlib.pyplot as plt

TAU = 2.737339

def Gamma(beta, tau=TAU):
    return 1.0 / (1.0 + tau * beta)**2


# ================================================================
# CLAIM 1: UV SELF-REGULATION
# ================================================================
#
# The claim: you can't pack infinite energy into the Clockfield
# because high β freezes time, preventing further oscillation.
#
# Check: what is the maximum frequency a wave can sustain in the
# Clockfield before self-freezing?
#
# A plane wave φ ~ A·exp(i(kx - ωt)) has β = A².
# The dispersion relation in the Clockfield is:
#   ω² = Γ²(A²) · (k² + V''(A²))
#   ω² = k²/(1+τA²)⁴ + ...
#
# As A increases, ω decreases. The wave slows down.
# At A² = Ξ/τ (freeze threshold), Γ → 0 and ω → 0.
#
# The maximum energy density the field can carry is:
#   β_max = Ξ/τ = (4/π)/τ
#
# Beyond this, the field freezes. No oscillation. No UV divergence.
#
# This is EXACT. It follows directly from Γ² multiplying the
# kinetic term. No additional assumption needed.

def max_frequency_vs_amplitude(tau=TAU):
    """The Clockfield dispersion relation: ω² = Γ²·k²"""
    A_sq = np.linspace(0, 2.0, 1000)
    G = Gamma(A_sq, tau)
    # For k=1 (arbitrary wavenumber), ω = Γ(A²) · k
    omega = G  # normalized to k=1
    Xi = 4.0 / np.pi
    beta_freeze = Xi / tau
    return A_sq, omega, beta_freeze


# VERDICT ON CLAIM 1:
# TRUE. The Clockfield has a built-in UV cutoff at β = Ξ/τ.
# This is not imposed — it emerges from the Γ² kinetic term.
# The cutoff energy density is E_max ~ Ξ/τ per mode.
# The total energy in a box of volume V with N modes is:
#   E_total < N · Ξ/τ < ∞
# The UV catastrophe doesn't occur because each mode self-regulates.


# ================================================================
# CLAIM 2: DIRECTIONAL THAW CASCADE
# ================================================================
#
# The claim: a frozen shell thaws preferentially from its thinnest
# point, and the cascade follows phase discontinuities.
#
# Check: the thaw probability at position x is:
#   P(thaw | x) ~ exp(-(β(x) - Ξ/τ)² / (2σ²))
#
# This is a Boltzmann-type thermal activation rate. It's maximized
# where β is closest to Ξ/τ — the shell boundary.
#
# The cascade direction depends on the interference of the released
# wave with adjacent frozen points. The key quantity is:
#   Δθ = θ(adjacent) - θ(thaw_point)
#
# If Δθ ≈ 0: constructive → β increases → freeze reinforced
# If Δθ ≈ π: destructive → β decreases → adjacent thaws
#
# So the cascade follows Δθ ≈ π contours — the phase discontinuities.
#
# For a vortex with winding n=1, the phase increases by 2π around
# the core. So there IS a preferred direction: the cascade propagates
# where the phase changes most rapidly, i.e., along the vortex filament.

def thaw_probability_map(beta_profile, sigma=0.1, tau=TAU):
    """Compute P(thaw) for a given β(r) profile."""
    Xi = 4.0 / np.pi
    threshold = Xi / tau
    # Activation energy: how far above threshold
    delta = np.maximum(beta_profile - threshold, 0)
    P_thaw = np.exp(-delta**2 / (2 * sigma**2))
    # Below threshold: already thawed, P=1
    P_thaw[beta_profile < threshold] = 1.0
    return P_thaw


def cascade_simulation_1d(N=500, tau=TAU, sigma=0.05, steps=200):
    """
    1D simulation of thaw cascade along a frozen shell.
    
    Initial: frozen shell with phase that winds from 0 to 2π.
    The phase discontinuity at 0/2π is where Δθ = π neighbors exist.
    The cascade should start at the thinnest point and propagate
    preferentially toward the phase discontinuity.
    """
    Xi = 4.0 / np.pi
    
    # Frozen shell: β varies from high (center) to threshold (edges)
    x = np.linspace(0, 2*np.pi, N)
    # Phase winds from 0 to 2π
    theta = x.copy()
    # Amplitude: peaked in center, falling to threshold at edges
    beta_0 = 2.0  # well above threshold
    beta = beta_0 * (0.5 + 0.5 * np.cos(x - np.pi))  # peak at π
    beta = np.maximum(beta, Xi/tau * 0.5)  # floor
    
    frozen = beta > Xi/tau
    thaw_history = []
    
    for t in range(steps):
        # Noise kicks
        noise = sigma * np.random.randn(N)
        
        # Check thaw condition
        for i in range(N):
            if frozen[i]:
                if beta[i] + noise[i] < Xi/tau:
                    # THAW EVENT
                    frozen[i] = False
                    # Release energy as wave
                    # Energy propagates to neighbors
                    for di in [-1, 1]:
                        j = (i + di) % N
                        if frozen[j]:
                            # Phase difference with neighbor
                            dtheta = theta[j] - theta[i]
                            # Interference: cos(dtheta) determines if constructive or destructive
                            interference = np.cos(dtheta)
                            # Modify neighbor's beta
                            beta[j] += 0.1 * interference  # constructive raises β
                            # destructive interference lowers it toward thaw
        
        thaw_history.append(frozen.copy())
    
    return x, theta, thaw_history


