#
# If the thaw is deterministic given the topology (which Claim 2
# suggests), and if the topology is fully determined by the wave
# configuration (which it is, by definition), then YES — the cycle
# is deterministic.
#
# BUT: the thaw is triggered by noise (TADS fluctuations). Noise
# is stochastic. So the TIMING of the thaw is random, even if the
# SEQUENCE is deterministic.
#
# This means: the limit cycle has a well-defined orbit in phase space
# but a stochastic period. The universe replays the same movie
# but at a variable speed.
#
# Is this actually a limit cycle? Yes, in the dynamical systems sense.
# The attractor is the topological configuration that survives the
# freeze-thaw cycle. The basin of attraction is all initial conditions
# that eventually settle onto this configuration. The stochastic
# period is just a random time reparametrization of the cycle.
#
# The fixed point of the cycle: the topology that maps to itself
# under freeze → thaw → refreeze. This is the self-consistent
# frozen configuration whose thaw cascade exactly regenerates the
# wave pattern that freezes into the same topology.
#
# Whether τ = 2.737 is the UNIQUE such fixed point is the claim
# that would connect this to the three paths to τ.

def check_freeze_thaw_symmetry(tau=TAU, beta_0=1.0, sigma=1.0, n=5000):
    """
    Check whether a frozen sech² profile, when thawed, produces
    a wave pattern whose re-freeze would give the same sech² profile.
    
    This is a self-consistency check for the limit cycle.
    
    Method: compute the energy released by thawing the profile,
    then check if that energy, propagating as a wave, would
    re-freeze into a similar profile.
    """
    r = np.linspace(1e-6, 15*sigma, n)
    beta = beta_0 * np.cosh(r/sigma)**(-2)
    G = Gamma(beta, tau)
    
    # Energy stored in the frozen profile
    dA_dr = -np.sqrt(beta_0)/sigma * np.cosh(r/sigma)**(-1) * np.tanh(r/sigma)
    E_grad = integrate.trapezoid(dA_dr**2 * 4*np.pi*r**2, r)
    E_pot = integrate.trapezoid((1.5*beta - 0.8*beta**2) * 4*np.pi*r**2, r)
    E_frozen = E_grad + E_pot
    
    # If this energy is released as a spherical wave, the wave has:
    # amplitude A_wave ~ sqrt(E_frozen / (4π R²)) at radius R
    # It will re-freeze when A_wave² > Ξ/τ
    # Re-freeze radius: R_refreeze = sqrt(E_frozen / (4π Ξ/τ))
    Xi = 4.0/np.pi
    R_refreeze = np.sqrt(E_frozen / (4*np.pi * Xi/tau))
    
    # Original profile width: σ
    # If R_refreeze ≈ σ, the cycle is self-consistent
    ratio = R_refreeze / sigma
    
    return E_frozen, R_refreeze, ratio


