"""
THAW CASCADE: 1D Simulation of Directional Evaporation
=======================================================

Demonstrates that a frozen Clockfield shell thaws preferentially
from its thinnest edge, with the cascade following phase topology.

The simulation:
- Creates a 1D frozen ring with a phase winding (θ goes 0 to 2π)
- Adds TADS noise
- Watches which points thaw first and how the cascade propagates
- Records the thaw front velocity and direction

The prediction: the cascade follows phase discontinuities (Δθ ≈ π),
not the β gradient. This is distinct from thermal Hawking radiation.

Author: Antti Luode (PerceptionLab) + Claude Opus (Anthropic)
"""

import numpy as np
from scipy import integrate
import matplotlib.pyplot as plt

TAU = 2.737339
XI = 4.0 / np.pi


def Gamma(beta, tau=TAU):
    return 1.0 / (1.0 + tau * beta)**2


def run_cascade(N=500, sigma=0.08, tau=TAU, steps=500, seed=42):
    """
    1D thaw cascade simulation.
    
    Setup: a ring of N points, each with:
    - beta(i): amplitude squared (frozen if > Xi/tau)
    - theta(i): phase angle (winds from 0 to 2π around the ring)
    
    The beta profile has a shallow spot (the "thinnest edge")
    and a deep frozen core.
    
    Returns the full history of frozen/thawed states.
    """
    rng = np.random.default_rng(seed)
    threshold = XI / tau
    
    # Phase winds from 0 to 2π
    x = np.linspace(0, 2*np.pi, N, endpoint=False)
    theta = x.copy()
    
    # Beta profile: peaked, with one shallow region
    # The shallow region is at x ≈ π (opposite to the deep core at x ≈ 0)
    beta = threshold * (1.5 + 1.0 * np.cos(x))  # peak at x=0, trough at x=π
    beta = np.maximum(beta, threshold * 0.3)  # don't go below 30% of threshold
    
    # Everything above threshold is frozen
    frozen = beta > threshold
    
    # Record
    frozen_history = [frozen.copy()]
    beta_history = [beta.copy()]
    thaw_events = []  # (step, position, phase_at_thaw)
    
    for t in range(steps):
        noise = sigma * rng.standard_normal(N)
        new_frozen = frozen.copy()
        new_beta = beta.copy()
        
        for i in range(N):
            if frozen[i]:
                # Check if noise kicks below threshold
                effective_beta = beta[i] + noise[i]
                if effective_beta < threshold:
                    # THAW EVENT
                    new_frozen[i] = False
                    thaw_events.append((t, i, theta[i]))
                    
                    # Energy release propagates to neighbors
                    # The released wave carries phase theta[i]
                    for di in [-1, 1]:
                        j = (i + di) % N
                        if frozen[j]:
                            # Phase difference determines interference
                            dtheta = theta[j] - theta[i]
                            interference = np.cos(dtheta)
                            
                            # Constructive (same phase): reinforce freeze
                            # Destructive (opposite phase): weaken freeze
                            energy_transfer = 0.15 * (1 - interference)  # max at Δθ=π
                            new_beta[j] -= energy_transfer * threshold
                            
                            # Also add a direct kick from released energy
                            new_beta[j] -= 0.05 * threshold
        
        frozen = new_frozen
        beta = np.maximum(new_beta, 0)
        frozen_history.append(frozen.copy())
        beta_history.append(beta.copy())
    
    return {
        'x': x,
        'theta': theta,
        'frozen_history': np.array(frozen_history),
        'beta_history': np.array(beta_history),
        'thaw_events': thaw_events,
        'threshold': threshold,
    }


def analyze_cascade(result):
    """Analyze the thaw cascade for directionality."""
    events = result['thaw_events']
    N = len(result['x'])
    
    if len(events) < 2:
        return None
    
    # Thaw front velocity: how fast does the thaw propagate?
    times = [e[0] for e in events]
    positions = [e[1] for e in events]
    phases = [e[2] for e in events]
    
    # Group by time to find the front
    first_thaw_time = times[0]
    first_thaw_pos = positions[0]
    first_thaw_phase = phases[0]
    
    # Which direction does the cascade go?
    # Positive direction: increasing index (increasing phase)
    # Negative direction: decreasing index (decreasing phase)
    pos_events = sum(1 for _, p, _ in events if (p - first_thaw_pos) % N < N//2 and p != first_thaw_pos)
    neg_events = sum(1 for _, p, _ in events if (first_thaw_pos - p) % N < N//2 and p != first_thaw_pos)
    
    return {
        'first_thaw_time': first_thaw_time,
        'first_thaw_pos': first_thaw_pos,
        'first_thaw_phase': first_thaw_phase,
        'total_events': len(events),
        'forward_events': pos_events,
        'backward_events': neg_events,
    }


def main():
    print("=" * 65)
    print("  THAW CASCADE — 1D Directional Evaporation")
    print("=" * 65)
    print()
    
    # Run multiple cascades with different noise levels
    sigmas = [0.05, 0.08, 0.12, 0.20]
    all_results = []
    
    for sig in sigmas:
        result = run_cascade(sigma=sig, steps=600)
        analysis = analyze_cascade(result)
        all_results.append((sig, result, analysis))
        
        if analysis:
            pct_frozen = result['frozen_history'][-1].sum() / len(result['x']) * 100
            print(f"σ = {sig:.2f}:")
            print(f"  First thaw at step {analysis['first_thaw_time']}, "
                  f"position {analysis['first_thaw_pos']}, "
                  f"phase {analysis['first_thaw_phase']:.2f}")
            print(f"  Total thaw events: {analysis['total_events']}")
            print(f"  Forward (↑phase): {analysis['forward_events']}, "
                  f"Backward (↓phase): {analysis['backward_events']}")
            print(f"  Final frozen fraction: {pct_frozen:.1f}%")
            print()
    
