"""
THE FIRST-ORDER CLOCKFIELD EQUATION
=====================================

dGamma/dbeta = -2*tau * Gamma^(3/2)

This is more fundamental than the Ouroboros ODE (d2G/db2 = 6*tau^2*G^2).
The second-order ODE has two solutions. The first-order ODE has one.
The second-order follows by differentiating the first.

This script:
1. Verifies the first-order structure to machine precision
2. Shows the two solutions to the second-order ODE (only one is physical)
3. Demonstrates the uniqueness of the physical solution
4. Computes the inverted RG flow
5. Verifies the UV self-regulation

Author: Claude Opus (Anthropic) — mathematical analysis from April 3, 2026
Physics: Antti Luode (PerceptionLab, Helsinki, Finland)

Do not hype. Do not lie. Just show.
"""

import numpy as np
from scipy import integrate, optimize
from scipy.integrate import solve_ivp
import matplotlib.pyplot as plt
import matplotlib.gridspec as gridspec

TAU = 2.737339
XI = 4.0 / np.pi


def Gamma(beta, tau=TAU):
    return 1.0 / (1.0 + tau * beta)**2

def dGamma(beta, tau=TAU):
    return -2.0 * tau / (1.0 + tau * beta)**3

def d2Gamma(beta, tau=TAU):
    return 6.0 * tau**2 / (1.0 + tau * beta)**4


# ================================================================
# PART 1: THE FIRST-ORDER STRUCTURE
# ================================================================

def verify_first_order(tau=TAU, n=100000):
    """
    Verify: dGamma/dbeta = -2*tau * Gamma^(3/2)
    
    This is the fundamental flow equation.
    The right side is determined entirely by the current value of Gamma.
    The rate of time-slowing depends only on how much time has already slowed.
    """
    beta = np.linspace(1e-6, 20.0, n)
    
    # Left side: d/dbeta [1/(1+tau*beta)^2]
    lhs = dGamma(beta, tau)
    
    # Right side: -2*tau * [1/(1+tau*beta)^2]^(3/2)
    # = -2*tau / (1+tau*beta)^3
    G = Gamma(beta, tau)
    rhs = -2.0 * tau * G**(3/2)
    
    max_error = np.max(np.abs(lhs - rhs))
    return max_error, lhs, rhs, beta, G


def show_uniqueness(tau=TAU):
    """
    Show that the second-order ODE has two solutions,
    but only one is physically acceptable.
    
    The physical requirements:
    1. Gamma(0) = 1  (vacuum: proper time normal)
    2. dGamma/dbeta < 0  (energy slows time)
    3. Gamma(inf) -> 0  (enough energy stops time)
    """
    beta_span = (0, 8)
    beta_eval = np.linspace(0, 8, 2000)
    
    def ode(beta, y):
        return [y[1], 6.0 * tau**2 * y[0]**2]
    
    # Physical branch: y(0)=1, y'(0)=-2*tau (decreasing)
    sol_phys = solve_ivp(ode, beta_span, [1.0, -2*tau], t_eval=beta_eval,
                          rtol=1e-12, atol=1e-14)
    
    # Unphysical branch: y(0)=1, y'(0)=+2*tau (increasing, time speeds up)
    sol_unphys = solve_ivp(ode, beta_span, [1.0, +2*tau], t_eval=beta_eval,
                            rtol=1e-12, atol=1e-14)
    
    # Exact solution
    G_exact = Gamma(beta_eval, tau)
    
    return beta_eval, sol_phys.y[0], sol_unphys.y[0], G_exact


def analytic_solution_derivation():
    """
    Show the analytic derivation step by step.
    
    dGamma/Gamma^(3/2) = -2*tau * dbeta
    
    Integrate:
    ∫ G^(-3/2) dG = -2*tau ∫ dbeta
    -2*G^(-1/2) = -2*tau*beta + C
    G^(-1/2) = tau*beta + C
    G = 1/(tau*beta + C)^2
    
    Gamma(0) = 1: C = 1
    Gamma(beta) = 1/(1+tau*beta)^2
    """
    print("ANALYTIC DERIVATION:")
    print("=" * 55)
    print()
    print("Start: dGamma/dbeta = -2*tau * Gamma^(3/2)")
    print()
    print("Separate: dGamma / Gamma^(3/2) = -2*tau * dbeta")
    print()
    print("Integrate: ∫ G^(-3/2) dG = -2*tau ∫ dbeta")
    print()
    print("          -2 * G^(-1/2) = -2*tau*beta + C")
    print()
    print("          G^(-1/2) = tau*beta + C")
    print()
    print("          G = 1/(tau*beta + C)^2")
    print()
    print("Apply Gamma(0) = 1: C = 1")
    print()
    print("  Gamma(beta) = 1/(1 + tau*beta)^2  ✓")
    print()
    print("This is the unique solution.")
    print()
    
    # Verify at several points
    betas = [0, 0.5, 1.0, 2.0, 5.0, 10.0]
    print("Verification:")
    for b in betas:
        analytic = 1/(1+TAU*b)**2
        from_formula = Gamma(b)
        print(f"  beta={b:5.1f}: analytic={analytic:.8f}, formula={from_formula:.8f}, "
              f"diff={abs(analytic-from_formula):.2e}")


# ================================================================
# PART 2: THE INVERTED RG FLOW
# ================================================================

def compute_rg_flow(tau_values=None, n=1000):
    """
    Compute the RG flow for the Clockfield metric.
    
    The 'coupling' is Gamma. The 'scale' is beta (energy density).
    beta function: dGamma/d(log beta) = beta * dGamma/dbeta = -2*tau*beta*Gamma^(3/2)
    
    Fixed points:
    - Gamma = 1 (UV: free vacuum, beta = 0)
    - Gamma = 0 (IR: frozen, beta = inf)
    
    INVERTED relative to standard QFT:
    Standard: UV = high energy = free, IR = low energy = confined
    Clockfield: UV = low beta = free, IR = high beta = frozen
    (Energy INCREASES toward the IR freeze, not away from it)
    """
    if tau_values is None:
        tau_values = [1.0, 2.0, TAU, 4.0, 8.0]
    
    beta = np.logspace(-3, 2, n)
    results = {}
    
    for tau in tau_values:
        G = Gamma(beta, tau)
        dG_dbeta = dGamma(beta, tau)
        # RG beta function (flow with energy scale)
        beta_fn = beta * dG_dbeta  # = dGamma/d(log beta)
        results[tau] = (beta, G, beta_fn)
    
    return results


def uv_regulation(tau=TAU, n=1000):
    """
    Demonstrate UV self-regulation.
    
    As beta -> Ξ/tau, omega -> 0.
    The dispersion relation is: omega^2 = Gamma^2 * k^2
    
    A mode cannot oscillate beyond the freeze threshold.
    This bounds the total energy in any finite volume.
    """
    beta = np.linspace(0, 2.0, n)
    G = Gamma(beta, tau)
    omega_over_k = G  # dispersion: omega/k = Gamma
    
    freeze_threshold = XI / tau
    omega_at_freeze = Gamma(freeze_threshold, tau)
    
    # Energy per mode is bounded by beta_freeze = Xi/tau
    # Total energy in box of volume V:
    # E_total < (number of modes) * beta_freeze
    # For continuous theory: this is still finite per mode
    
    return beta, omega_over_k, freeze_threshold, omega_at_freeze


# ================================================================
# PART 3: CONNECTING TO THE THAW CASCADE
# ================================================================

def thaw_probability_and_direction(N=1000, sigma=0.08, tau=TAU):
    """
    Show why the thaw cascade is directional.
    
    The thaw probability depends on beta (how far above threshold).
    The cascade direction depends on phase differences (constructive/destructive).
    
    Key: phase differences are small for NEARBY points (same direction)
    but large (Δθ ≈ π) for DISTANT points.
    The ENERGY PROPAGATION from the first thaw point can reach distant points
    and cause destructive interference there.
    """
    threshold = XI / tau
    
    # 1D frozen ring with phase winding
    x = np.linspace(0, 2*np.pi, N, endpoint=False)
    theta = x.copy()
    
    # Beta profile: minimum at x=pi (the "thinnest edge")
    beta = threshold * (1.5 + 1.0 * np.cos(x))
    beta = np.maximum(beta, threshold * 0.3)
    
    # Thaw probability at each point
    delta = np.maximum(beta - threshold, 0)
    P_thaw = np.exp(-delta**2 / (2 * sigma**2))
    P_thaw[beta < threshold] = 1.0
    
    # First thaw at the thinnest point (x=pi, index N//2)
    i0 = N // 2
    theta_0 = theta[i0]
    
    # Effect on each other point from energy released at i0
    # delta_theta(j) = theta[j] - theta[i0]
    # Interference = cos(delta_theta)
    # Positive interference: reinforces freeze
    # Negative (Δθ near π): weakens freeze
    delta_theta = theta - theta_0
    interference = np.cos(delta_theta)
    
    # Points CLOSE to phase π away from theta_0 get destructively interfered
    # theta_0 = pi, so theta[j] = 0 or 2π have Δθ = ±pi
    # These are at x=0 and x=2π (the same point on the ring)
    # That's i=0 (opposite side of the ring from i0=N/2)
    
    return x, theta, beta, P_thaw, interference, threshold, i0


